     5→/**
     6→ * 日志管理工具类
     7→ *
     8→ * 统一管理所有日志输出，自动添加 TAG 前缀
     9→ * 提供：
    10→ * - d(): Debug 日志
    11→ * - e(): Error 日志
    12→ * - i(): Info 日志
    13→ * - w(): Warning 日志
    14→ */
    15→object Logger {
    16→
    17→    private const val DEFAULT_TAG = "CourtAssistant"
    18→    private const val isDebug = true
    19→
    20→    /**
    21→     * Debug 日志
    22→     * @param tag 标签
    23→     * @param message 消息内容
    24→     */
    25→    fun d(tag: String = DEFAULT_TAG, message: String) {
    26→        if (isDebug) {
    27→            Log.d(tag, message)
    28→        }
    29→    }
    30→
    31→    /**
    32→     * Error 日志
    33→     * @param tag 标签
    34→     * @param message 消息内容
    35→     */
    36→    fun e(tag: String = DEFAULT_TAG, message: String) {
    37→        if (isDebug) {
    38→            Log.e(tag, message)
    39→        }
    40→    }
    41→
    42→    /**
    43→     * Error 日志（带异常）
    44→     * @param tag 标签
    45→     * @param message 消息内容
    46→     * @param throwable 异常对象
    47→     */
    48→    fun e(tag: String = DEFAULT_TAG, message: String, throwable: Throwable) {
    49→        if (isDebug) {
    50→            Log.e(tag, message, throwable)
    51→        }
    52→    }
    53→
    54→    /**
    55→     * Info 日志
    56→     * @param tag 标签
    57→     * @param message 消息内容
    58→     */
    59→    fun i(tag: String = DEFAULT_TAG, message: String) {
    60→        if (isDebug) {
    61→            Log.i(tag, message)
    62→        }
    63→    }
    64→
    65→    /**
    66→     * Warning 日志
    67→     * @param tag 标签
    68→     * @param message 消息内容
    69→     */
    70→    fun w(tag: String = DEFAULT_TAG, message: String) {
    71→        if (isDebug) {
    72→            Log.w(tag, message)
    73→        }
    74→    }
    75→
    76→    /**
    77→     * Warning 日志（带异常）
    78→     * @param tag 标签
    79→     * @param message 消息内容
    80→     * @param throwable 异常对象
    81→     */
    82→    fun w(tag: String = DEFAULT_TAG, message: String, throwable: Throwable) {
    83→        if (isDebug) {
    84→            Log.w(tag, message, throwable)
    85→        }
    86→    }
    87→
    88→    /**
    89→     * Verbose 日志
    90→     * @param tag 标签
    91→     * @param message 消息内容
    92→     */
    93→    fun v(tag: String = DEFAULT_TAG, message: String) {
    94→        if (isDebug) {
    95→            Log.v(tag, message)
    96→        }
    97→    }
    98→
    99→    /**
   100→     * Assert 日志
   101→     * @param tag 标签
   102→     * @param message 消息内容
   103→     */
   104→    fun wtf(tag: String = DEFAULT_TAG, message: String) {
   105→        if (isDebug) {
   106→            Log.wtf(tag, message)
   107→        }
   108→    }
