package com.shanfuchun.courtassistant.util.ui

import android.content.Context
import android.widget.Toast
import androidx.annotation.StringRes

/**
 * Toast 显示工具类
 *
 * 统一管理所有 Toast 显示操作，消除重复代码
 * 提供：
 * - showSuccess(): 显示成功消息
 * - showError(): 显示错误消息
 * - showInfo(): 显示信息消息
 */
object ToastUtils {

    private var context: Context? = null

    /**
     * 初始化 Context（必须在 Application 类中调用）
     * @param context 上下文对象
     */
    fun init(context: Context) {
        this.context = context.applicationContext
    }

    /**
     * 显示成功消息
     * @param message 消息内容
     */
    fun showSuccess(message: String) {
        show(message, Toast.LENGTH_SHORT)
    }

    /**
     * 显示成功消息（资源ID）
     * @param resId 消息资源ID
     */
    fun showSuccess(@StringRes resId: Int) {
        context?.let { show(it.getString(resId), Toast.LENGTH_SHORT) }
    }

    /**
     * 显示错误消息
     * @param message 消息内容
     */
    fun showError(message: String) {
        show(message, Toast.LENGTH_LONG)
    }

    /**
     * 显示错误消息（资源ID）
     * @param resId 消息资源ID
     */
    fun showError(@StringRes resId: Int) {
        context?.let { show(it.getString(resId), Toast.LENGTH_LONG) }
    }

    /**
     * 显示信息消息
     * @param message 消息内容
     */
    fun showInfo(message: String) {
        show(message, Toast.LENGTH_SHORT)
    }

    /**
     * 显示信息消息（资源ID）
     * @param resId 消息资源ID
     */
    fun showInfo(@StringRes resId: Int) {
        context?.let { show(it.getString(resId), Toast.LENGTH_SHORT) }
    }

    /**
     * 显示警告消息
     * @param message 消息内容
     */
    fun showWarning(message: String) {
        show(message, Toast.LENGTH_SHORT)
    }

    /**
     * 使用指定上下文显示 Toast
     * @param context 上下文对象
     * @param message 消息内容
     * @param duration 显示时长
     */
    fun show(context: Context, message: String, duration: Int = Toast.LENGTH_SHORT) {
        Toast.makeText(context.applicationContext, message, duration).show()
    }

    /**
     * 内部 Toast 显示方法
     * @param message 消息内容
     * @param duration 显示时长
     */
    private fun show(message: String, duration: Int) {
        context?.let {
            Toast.makeText(it, message, duration).show()
        }
    }

    /**
     * 检查是否已初始化
     * @return 是否已初始化
     */
    fun isInitialized(): Boolean {
        return context != null
    }
}

package com.shanfuchun.courtassistant.util.log

import android.util.Log
import android.util.Log.VERBOSE
import com.shanfuchun.courtassistant.BuildConfig

/**
 * 日志管理工具类
 *
 * 统一管理所有日志输出，自动添加 TAG 前缀
 * 提供：
 * - d(): Debug 日志
 * - e(): Error 日志
 * - i(): Info 日志
 * - w(): Warning 日志
 */
object Logger {

    private const val DEFAULT_TAG = "CourtAssistant"
    private val isDebug: Boolean = BuildConfig.DEBUG

    /**
     * Debug 日志
     * @param tag 标签
     * @param message 消息内容
     */
    fun d(tag: String = DEFAULT_TAG, message: String) {
        if (isDebug) {
            Log.d(tag, message)
        }
    }

    /**
     * Debug 日志（格式化）
     * @param tag 标签
     * @param format 格式字符串
     * @param args 参数
     */
    fun d(tag: String = DEFAULT_TAG, format: String, vararg args: Any) {
        if (isDebug) {
            Log.d(tag, String.format(format, *args))
        }
    }

    /**
     * Error 日志
     * @param tag 标签
     * @param message 消息内容
     */
    fun e(tag: String = DEFAULT_TAG, message: String) {
        if (isDebug) {
            Log.e(tag, message)
        }
    }

    /**
     * Error 日志（带异常）
     * @param tag 标签
     * @param message 消息内容
     * @param throwable 异常对象
     */
    fun e(tag: String = DEFAULT_TAG, message: String, throwable: Throwable?) {
        if (isDebug) {
            Log.e(tag, message, throwable)
        }
    }

    /**
     * Error 日志（仅异常）
     * @param tag 标签
     * @param throwable 异常对象
     */
    fun e(tag: String = DEFAULT_TAG, throwable: Throwable?) {
        if (isDebug) {
            Log.e(tag, throwable?.message ?: "Unknown error", throwable)
        }
    }

    /**
     * Info 日志
     * @param tag 标签
     * @param message 消息内容
     */
    fun i(tag: String = DEFAULT_TAG, message: String) {
        if (isDebug) {
            Log.i(tag, message)
        }
    }

    /**
     * Warning 日志
     * @param tag 标签
     * @param message 消息内容
     */
    fun w(tag: String = DEFAULT_TAG, message: String) {
        if (isDebug) {
            Log.w(tag, message)
        }
    }

    /**
     * Warning 日志（带异常）
     * @param tag 标签
     * @param message 消息内容
     * @param throwable 异常对象
     */
    fun w(tag: String = DEFAULT_TAG, message: String, throwable: Throwable?) {
        if (isDebug) {
            Log.w(tag, message, throwable)
        }
    }

    /**
     * Verbose 日志
     * @param tag 标签
     * @param message 消息内容
     */
    fun v(tag: String = DEFAULT_TAG, message: String) {
        if (isDebug) {
            Log.v(tag, message)
        }
    }

    /**
     * Assert 日志（What a Terrible Failure）
     * @param tag 标签
     * @param message 消息内容
     */
    fun wtf(tag: String = DEFAULT_TAG, message: String) {
        if (isDebug) {
            Log.wtf(tag, message)
        }
    }

    /**
     * Assert 日志（带异常）
     * @param tag 标签
     * @param message 消息内容
     * @param throwable 异常对象
     */
    fun wtf(tag: String = DEFAULT_TAG, message: String, throwable: Throwable?) {
        if (isDebug) {
            Log.wtf(tag, message, throwable)
        }
    }

    /**
     * 格式化日志输出
     * @param tag 标签
     * @param format 格式字符串
     * @param args 参数
     */
    fun format(tag: String = DEFAULT_TAG, format: String, vararg args: Any) {
        if (isDebug) {
            val message = try {
                String.format(format, *args)
            } catch (e: Exception) {
                format
            }
            Log.d(tag, message)
        }
    }

    /**
     * JSON 格式化日志
     * @param tag 标签
     * @param json JSON 字符串
     */
    fun json(tag: String = DEFAULT_TAG, json: String) {
        if (isDebug) {
            val formattedJson = try {
                formatJson(json)
            } catch (e: Exception) {
                json
            }
            formattedJson.split("\n").forEach { line ->
                Log.d(tag, line)
            }
        }
    }

    /**
     * 格式化 JSON 字符串
     */
    private fun formatJson(json: String): String {
        return try {
            val jsonObject = org.json.JSONObject(json)
            jsonObject.toString(2)
        } catch (e: Exception) {
            json
        }
    }

    /**
     * 获取调用堆栈信息
     * @param depth 堆栈深度（默认为调用者的上一级）
     * @return 堆栈信息字符串
     */
    fun getStackTrace(depth: Int = 1): String {
        if (!isDebug) return ""

        return try {
            val stackTrace = Thread.currentThread().stackTrace
            if (stackTrace.size > depth + 1) {
                val element = stackTrace[depth + 1]
                "(${element.fileName}:${element.lineNumber}) ${element.methodName}"
            } else {
                ""
            }
        } catch (e: Exception) {
            ""
        }
    }
}

package com.shanfuchun.courtassistant.util.date

import java.text.SimpleDateFormat
import java.util.*

/**
 * 日期格式化工具类
 *
 * 统一管理所有日期格式化操作，消除重复代码
 * 提供3种常用的日期格式化方法：
 * - formatDateTime: 完整日期时间格式 (yyyy-MM-dd HH:mm)
 * - formatDateShort: 简短日期格式 (MM-dd HH:mm)
 * - formatTimeOnly: 仅时间格式 (HH:mm)
 */
object DateUtils {

    private val dateTimeFormat = SimpleDateFormat("yyyy-MM-dd HH:mm", Locale.CHINA)
    private val dateShortFormat = SimpleDateFormat("MM-dd HH:mm", Locale.CHINA)
    private val timeFormat = SimpleDateFormat("HH:mm", Locale.CHINA)
    private val fullDateFormat = SimpleDateFormat("yyyy年MM月dd日 HH:mm", Locale.CHINA)
    private val monthDayFormat = SimpleDateFormat("MM月dd日", Locale.CHINA)

    /**
     * 格式化完整日期时间
     * @param date 日期对象
     * @return 格式化后的字符串 (yyyy-MM-dd HH:mm)
     */
    fun formatDateTime(date: Date): String {
        return dateTimeFormat.format(date)
    }

    /**
     * 格式化中文完整日期时间
     * @param date 日期对象
     * @return 格式化后的字符串 (yyyy年MM月dd日 HH:mm)
     */
    fun formatFullDateTime(date: Date): String {
        return fullDateFormat.format(date)
    }

    /**
     * 格式化简短日期时间
     * @param date 日期对象
     * @return 格式化后的字符串 (MM-dd HH:mm)
     */
    fun formatDateShort(date: Date): String {
        return dateShortFormat.format(date)
    }

    /**
     * 仅格式化时间部分
     * @param date 日期对象
     * @return 格式化后的字符串 (HH:mm)
     */
    fun formatTimeOnly(date: Date): String {
        return timeFormat.format(date)
    }

    /**
     * 格式化月日
     * @param date 日期对象
     * @return 格式化后的字符串 (MM月dd日)
     */
    fun formatMonthDay(date: Date): String {
        return monthDayFormat.format(date)
    }

    /**
     * 从时间戳格式化完整日期时间
     * @param timestamp 时间戳（毫秒）
     * @return 格式化后的字符串 (yyyy-MM-dd HH:mm)
     */
    fun formatDateTime(timestamp: Long): String {
        return if (timestamp > 0) {
            formatDateTime(Date(timestamp))
        } else {
            ""
        }
    }

    /**
     * 从时间戳格式化中文完整日期时间
     * @param timestamp 时间戳（毫秒）
     * @return 格式化后的字符串 (yyyy年MM月dd日 HH:mm)
     */
    fun formatFullDateTime(timestamp: Long): String {
        return if (timestamp > 0) {
            formatFullDateTime(Date(timestamp))
        } else {
            ""
        }
    }

    /**
     * 从时间戳格式化简短日期时间
     * @param timestamp 时间戳（毫秒）
     * @return 格式化后的字符串 (MM-dd HH:mm)
     */
    fun formatDateShort(timestamp: Long): String {
        return if (timestamp > 0) {
            formatDateShort(Date(timestamp))
        } else {
            ""
        }
    }

    /**
     * 从时间戳格式化时间部分
     * @param timestamp 时间戳（毫秒）
     * @return 格式化后的字符串 (HH:mm)
     */
    fun formatTimeOnly(timestamp: Long): String {
        return if (timestamp > 0) {
            formatTimeOnly(Date(timestamp))
        } else {
            ""
        }
    }

    /**
     * 从时间戳格式化月日
     * @param timestamp 时间戳（毫秒）
     * @return 格式化后的字符串 (MM月dd日)
     */
    fun formatMonthDay(timestamp: Long): String {
        return if (timestamp > 0) {
            formatMonthDay(Date(timestamp))
        } else {
            ""
        }
    }

    /**
     * 解析日期字符串为 Date 对象
     * @param dateStr 日期字符串
     * @param pattern 格式模式
     * @return Date 对象，解析失败返回 null
     */
    fun parse(dateStr: String, pattern: String = "yyyy-MM-dd HH:mm"): Date? {
        return try {
            SimpleDateFormat(pattern, Locale.CHINA).parse(dateStr)
        } catch (e: Exception) {
            null
        }
    }

    /**
     * 获取相对时间描述
     * @param timestamp 时间戳（毫秒）
     * @return 相对时间描述（如：刚刚、5分钟前、今天 10:30）
     */
    fun getRelativeTime(timestamp: Long): String {
        if (timestamp <= 0) return ""

        val now = System.currentTimeMillis()
        val diff = now - timestamp

        return when {
            diff < 60 * 1000 -> "刚刚"
            diff < 60 * 60 * 1000 -> "${diff / (60 * 1000)}分钟前"
            diff < 24 * 60 * 60 * 1000 -> {
                val hours = diff / (60 * 60 * 1000)
                if (hours < 6) "${hours}小时前"
                else "今天 ${formatTimeOnly(timestamp)}"
            }
            diff < 48 * 60 * 60 * 1000 -> "昨天 ${formatTimeOnly(timestamp)}"
            else -> formatDateShort(timestamp)
        }
    }

    /**
     * 获取今天的开始时间（00:00:00）
     * @return 今天开始的时间戳
     */
    fun getTodayStart(): Long {
        val calendar = Calendar.getInstance()
        calendar.set(Calendar.HOUR_OF_DAY, 0)
        calendar.set(Calendar.MINUTE, 0)
        calendar.set(Calendar.SECOND, 0)
        calendar.set(Calendar.MILLISECOND, 0)
        return calendar.timeInMillis
    }

    /**
     * 获取今天的结束时间（23:59:59）
     * @return 今天结束的时间戳
     */
    fun getTodayEnd(): Long {
        val calendar = Calendar.getInstance()
        calendar.set(Calendar.HOUR_OF_DAY, 23)
        calendar.set(Calendar.MINUTE, 59)
        calendar.set(Calendar.SECOND, 59)
        calendar.set(Calendar.MILLISECOND, 999)
        return calendar.timeInMillis
    }

    /**
     * 判断是否是今天
     * @param timestamp 时间戳
     * @return 是否是今天
     */
    fun isToday(timestamp: Long): Boolean {
        val date = Date(timestamp)
        val today = Date()
        return date.day == today.day &&
                date.month == today.month &&
                date.year == today.year
    }

    /**
     * 判断是否是昨天
     * @param timestamp 时间戳
     * @return 是否是昨天
     */
    fun isYesterday(timestamp: Long): Boolean {
        val yesterday = System.currentTimeMillis() - 24 * 60 * 60 * 1000
        val date = Date(timestamp)
        val yesterdayDate = Date(yesterday)
        return date.day == yesterdayDate.day &&
                date.month == yesterdayDate.month &&
                date.year == yesterdayDate.year
    }
}

package com.shanfuchun.courtassistant.util.file

import android.content.Context
import android.net.Uri
import android.os.Environment
import android.webkit.MimeTypeMap
import androidx.core.content.FileProvider
import java.io.File
import java.io.FileInputStream
import java.io.FileOutputStream
import java.io.IOException
import java.text.DecimalFormat
import java.security.MessageDigest

/**
 * 文件操作工具类
 *
 * 统一管理文件相关操作，消除重复代码
 * 提供：
 * - ensureDir(): 确保目录存在，不存在则创建
 * - formatSize(): 格式化文件大小显示
 * - getFileExtension(): 获取文件扩展名
 * - createPdfDirectory(): 创建PDF目录
 * - getMimeType(): 获取文件MIME类型
 * - copyFile(): 复制文件
 * - getFileMd5(): 计算文件MD5
 */
object FileUtils {

    /**
     * 确保目录存在，不存在则创建
     * @param file 目录文件对象
     * @return 是否成功
     */
    fun ensureDir(file: File): Boolean {
        return if (!file.exists()) {
            file.mkdirs()
        } else {
            file.isDirectory
        }
    }

    /**
     * 确保父目录存在
     * @param file 文件对象
     * @return 是否成功
     */
    fun ensureParentDir(file: File): Boolean {
        return file.parentFile?.let { ensureDir(it) } ?: true
    }

    /**
     * 格式化文件大小显示
     * @param size 文件大小（字节）
     * @return 格式化后的大小字符串（B/KB/MB/GB）
     */
    fun formatSize(size: Long): String {
        if (size <= 0) return "0 B"

        val units = arrayOf("B", "KB", "MB", "GB", "TB")
        var index = 0
        var fileSize = size.toDouble()

        while (fileSize >= 1024 && index < units.size - 1) {
            fileSize /= 1024
            index++
        }

        val df = DecimalFormat("#.##")
        return "${df.format(fileSize)} ${units[index]}"
    }

    /**
     * 获取文件扩展名
     * @param file 文件对象
     * @return 扩展名（包含点号），如果没有扩展名返回空字符串
     */
    fun getFileExtension(file: File): String {
        return getFileExtension(file.name)
    }

    /**
     * 从文件名获取扩展名
     * @param filename 文件名
     * @return 扩展名（包含点号），如果没有扩展名返回空字符串
     */
    fun getFileExtension(filename: String): String {
        val lastDot = filename.lastIndexOf('.')
        return if (lastDot > 0) {
            filename.substring(lastDot).lowercase()
        } else {
            ""
        }
    }

    /**
     * 获取不含扩展名的文件名
     * @param filename 文件名
     * @return 不含扩展名的文件名
     */
    fun getFileNameWithoutExtension(filename: String): String {
        val lastDot = filename.lastIndexOf('.')
        return if (lastDot > 0) {
            filename.substring(0, lastDot)
        } else {
            filename
        }
    }

    /**
     * 创建PDF输出目录
     * @param baseDir 基础目录
     * @return PDF目录文件对象
     */
    fun createPdfDirectory(baseDir: File): File {
        val pdfDir = File(baseDir, "CourtAssistant/PDFs")
        ensureDir(pdfDir)
        return pdfDir
    }

    /**
     * 获取应用外部存储目录
     * @param context 上下文
     * @return 外部存储目录
     */
    fun getAppExternalDir(context: Context): File {
        val dir = if (Environment.getExternalStorageState() == Environment.MEDIA_MOUNTED) {
            File(context.getExternalFilesDir(null), "CourtAssistant")
        } else {
            File(context.filesDir, "CourtAssistant")
        }
        ensureDir(dir)
        return dir
    }

    /**
     * 获取文件MIME类型
     * @param file 文件对象
     * @return MIME类型字符串
     */
    fun getMimeType(file: File): String? {
        return getMimeType(file.name)
    }

    /**
     * 从文件名获取MIME类型
     * @param filename 文件名
     * @return MIME类型字符串
     */
    fun getMimeType(filename: String): String? {
        val extension = getFileExtension(filename).removePrefix(".")
        if (extension.isEmpty()) return null

        return MimeTypeMap.getSingleton().getMimeTypeFromExtension(extension)
    }

    /**
     * 复制文件
     * @param src 源文件
     * @param dest 目标文件
     * @return 是否成功
     */
    fun copyFile(src: File, dest: File): Boolean {
        return try {
            ensureParentDir(dest)
            FileInputStream(src).use { input ->
                FileOutputStream(dest).use { output ->
                    input.copyTo(output)
                }
            }
            true
        } catch (e: IOException) {
            e.printStackTrace()
            false
        }
    }

    /**
     * 移动文件
     * @param src 源文件
     * @param dest 目标文件
     * @return 是否成功
     */
    fun moveFile(src: File, dest: File): Boolean {
        return if (src.renameTo(dest)) {
            true
        } else {
            // 重命名失败时尝试复制后删除
            if (copyFile(src, dest)) {
                src.delete()
            } else {
                false
            }
        }
    }

    /**
     * 删除文件或目录
     * @param file 文件或目录
     * @return 是否成功
     */
    fun deleteFile(file: File): Boolean {
        return if (file.isDirectory) {
            file.listFiles()?.forEach { deleteFile(it) }
            file.delete()
        } else {
            file.delete()
        }
    }

    /**
     * 获取文件大小（目录则递归计算）
     * @param file 文件或目录
     * @return 文件大小（字节）
     */
    fun getFileSize(file: File): Long {
        return if (file.isDirectory) {
            file.listFiles()?.sumOf { getFileSize(it) } ?: 0L
        } else {
            file.length()
        }
    }

    /**
     * 计算文件MD5值
     * @param file 文件对象
     * @return MD5字符串（32位小写）
     */
    fun getFileMd5(file: File): String? {
        return try {
            val md = MessageDigest.getInstance("MD5")
            FileInputStream(file).use { input ->
                val buffer = ByteArray(8192)
                var bytesRead: Int
                while (input.read(buffer).also { bytesRead = it } != -1) {
                    md.update(buffer, 0, bytesRead)
                }
            }
            val digest = md.digest()
            digest.joinToString("") { "%02x".format(it) }
        } catch (e: Exception) {
            e.printStackTrace()
            null
        }
    }

    /**
     * 通过 FileProvider 创建文件 URI
     * @param context 上下文
     * @param file 文件对象
     * @return 文件的 URI
     */
    fun createFileUri(context: Context, file: File): Uri {
        return FileProvider.getUriForFile(
            context,
            "${context.packageName}.fileprovider",
            file
        )
    }

    /**
     * 检查文件是否存在
     * @param file 文件对象
     * @return 是否存在
     */
    fun exists(file: File?): Boolean {
        return file != null && file.exists()
    }

    /**
     * 检查文件是否可读
     * @param file 文件对象
     * @return 是否可读
     */
    fun canRead(file: File?): Boolean {
        return exists(file) && file!!.canRead()
    }

    /**
     * 检查文件是否可写
     * @param file 文件对象
     * @return 是否可写
     */
    fun canWrite(file: File?): Boolean {
        return exists(file) && file!!.canWrite()
    }

    /**
     * 获取缓存目录
     * @param context 上下文
     * @return 缓存目录
     */
    fun getCacheDir(context: Context): File {
        val cacheDir = File(context.cacheDir, "CourtAssistant")
        ensureDir(cacheDir)
        return cacheDir
    }

    /**
     * 清空缓存目录
     * @param context 上下文
     * @return 是否成功
     */
    fun clearCache(context: Context): Boolean {
        val cacheDir = getCacheDir(context)
        return if (cacheDir.exists()) {
            cacheDir.listFiles()?.forEach { deleteFile(it) }
            true
        } else {
            true
        }
    }
}

package com.shanfuchun.courtassistant.util.file

import android.content.Context
import android.net.Uri
import android.provider.DocumentsContract
import android.provider.OpenableColumns
import androidx.core.content.FileProvider
import java.io.File

/**
 * URI 处理工具类
 *
 * 统一管理所有 URI 处理操作，消除 FileProvider 重复代码
 * 提供：
 * - createFileUri(): 创建文件 URI
 * - createProviderUri(): 创建 Provider URI
 * - getFileName(): 从 URI 获取文件名
 * - getFileSize(): 从 URI 获取文件大小
 * - uriToFile(): 将 URI 转换为 File
 */
object UriUtils {

    /**
     * 通过 FileProvider 创建文件 URI
     * @param context 上下文
     * @param file 文件对象
     * @return 文件的 URI
     */
    fun createFileUri(context: Context, file: File): Uri {
        return FileProvider.getUriForFile(
            context,
            "${context.packageName}.fileprovider",
            file
        )
    }

    /**
     * 创建 Provider URI
     * @param context 上下文
     * @param path 文件路径
     * @return URI
     */
    fun createProviderUri(context: Context, path: String): Uri {
        return createFileUri(context, File(path))
    }

    /**
     * 从 URI 获取文件名
     * @param context 上下文
     * @param uri 文件 URI
     * @return 文件名，获取失败返回 null
     */
    fun getFileName(context: Context, uri: Uri): String? {
        // 首先尝试从 URI 直接获取
        uri.lastPathSegment?.let { return it }

        // 尝试从 ContentResolver 获取
        return context.contentResolver.query(uri, null, null, null, null)?.use { cursor ->
            if (cursor.moveToFirst()) {
                val nameIndex = cursor.getColumnIndex(OpenableColumns.DISPLAY_NAME)
                if (nameIndex >= 0) {
                    cursor.getString(nameIndex)
                } else {
                    null
                }
            } else {
                null
            }
        }
    }

    /**
     * 从 URI 获取文件大小
     * @param context 上下文
     * @param uri 文件 URI
     * @return 文件大小（字节），获取失败返回 -1
     */
    fun getFileSize(context: Context, uri: Uri): Long {
        return context.contentResolver.query(uri, null, null, null, null)?.use { cursor ->
            if (cursor.moveToFirst()) {
                val sizeIndex = cursor.getColumnIndex(OpenableColumns.SIZE)
                if (sizeIndex >= 0) {
                    cursor.getLong(sizeIndex)
                } else {
                    -1L
                }
            } else {
                -1L
            }
        } ?: -1L
    }

    /**
     * 判断 URI 是否是文件类型
     * @param uri 文件 URI
     * @return 是否是文件类型
     */
    fun isFileUri(uri: Uri): Boolean {
        return "file".equals(uri.scheme, ignoreCase = true)
    }

    /**
     * 判断 URI 是否是 Content 类型
     * @param uri 文件 URI
     * @return 是否是 Content 类型
     */
    fun isContentUri(uri: Uri): Boolean {
        return "content".equals(uri.scheme, ignoreCase = true)
    }

    /**
     * 尝试将 URI 转换为 File
     * 注意：此方法仅适用于 file:// 类型的 URI
     * @param uri 文件 URI
     * @return File 对象，转换失败返回 null
     */
    fun uriToFile(uri: Uri): File? {
        return if (isFileUri(uri)) {
            File(uri.path ?: return null)
        } else {
            null
        }
    }

    /**
     * 获取 MIME 类型
     * @param context 上下文
     * @param uri 文件 URI
     * @return MIME 类型字符串
     */
    fun getMimeType(context: Context, uri: Uri): String? {
        return context.contentResolver.getType(uri)
    }

    /**
     * 判断 URI 是否存在
     * @param context 上下文
     * @param uri 文件 URI
     * @return 是否存在
     */
    fun exists(context: Context, uri: Uri): Boolean {
        return try {
            context.contentResolver.openInputStream(uri)?.use { true } ?: false
        } catch (e: Exception) {
            false
        }
    }

    /**
     * 判断是否是文档 URI
     * @param uri 文件 URI
     * @return 是否是文档 URI
     */
    fun isDocumentUri(uri: Uri): Boolean {
        return DocumentsContract.isDocumentUri(null, uri)
    }

    /**
     * 检查 URI 授权
     * @param context 上下文
     * @param uri 文件 URI
     * @param readPermission 读权限
     * @return 是否有授权
     */
    @Deprecated("Use checkUriPermission instead")
    fun isUriReadGranted(context: Context, uri: Uri, readPermission: String): Boolean {
        return context.checkCallingOrSelfUriPermission(uri, Intent.FLAG_GRANT_READ_URI_PERMISSION) ==
                android.content.pm.PackageManager.PERMISSION_GRANTED
    }

    /**
     * 临时授予 URI 读取权限
     * @param context 上下文
     * @param uri 文件 URI
     * @return 是否成功
     */
    fun grantReadPermission(context: Context, uri: Uri): Boolean {
        return try {
            context.grantUriPermission(
                context.packageName,
                uri,
                android.content.Intent.FLAG_GRANT_READ_URI_PERMISSION
            )
            true
        } catch (e: Exception) {
            false
        }
    }

    /**
     * 从路径创建 File URI
     * @param path 文件路径
     * @return File URI
     */
    fun fromFile(path: String): Uri {
        return Uri.fromFile(File(path))
    }

    /**
     * 从 File 对象创建 URI
     * @param file 文件对象
     * @return URI
     */
    fun fromFile(file: File): Uri {
        return Uri.fromFile(file)
    }

    /**
     * 解析 URI 获取文件路径
     * 注意：此方法不保证适用于所有 URI 类型
     * @param uri 文件 URI
     * @return 文件路径字符串
     */
    fun getPath(uri: Uri): String? {
        return uri.path
    }

    /**
     * 创建带权限的 URI
     * @param context 上下文
     * @param file 文件对象
     * @return 带 FLAG_GRANT_READ_URI_PERMISSION 权限的 URI
     */
    fun createAuthorizedUri(context: Context, file: File): Uri {
        val uri = createFileUri(context, file)
        grantReadPermission(context, uri)
        return uri
    }
}

package com.shanfuchun.courtassistant.util.network

import android.content.Context
import android.net.ConnectivityManager
import android.net.Network
import android.net.NetworkCapabilities
import android.net.NetworkRequest
import android.os.Build
import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import kotlinx.coroutines.suspendCancellableCoroutine
import java.net.HttpURLConnection
import java.net.URL
import kotlin.coroutines.resume
import kotlin.coroutines.resumeWithException

/**
 * 网络状态辅助类
 *
 * 提供网络状态检测功能：
 * - 检查网络连接状态
 * - 判断网络类型（WiFi/Mobile）
 * - 网络状态监听
 * - 网络可用性测试
 */
object NetworkHelper {

    private lateinit var appContext: Context
    private val connectivityManager get() = appContext.getSystemService(Context.CONNECTIVITY_SERVICE) as ConnectivityManager

    // 网络状态 LiveData
    private val _networkState = MutableLiveData<NetworkState>()
    val networkState: LiveData<NetworkState> get() = _networkState

    private var networkCallback: ConnectivityManager.NetworkCallback? = null

    /**
     * 网络状态数据类
     */
    data class NetworkState(
        val isConnected: Boolean,
        val isWifi: Boolean = false,
        val isMobile: Boolean = false,
        val isAvailable: Boolean = false
    ) {
        companion object {
            fun disconnected() = NetworkState(false)
        }
    }

    /**
     * 初始化（必须在 Application 类中调用）
     * @param context 应用上下文
     */
    fun init(context: Context) {
        appContext = context.applicationContext
    }

    /**
     * 检查网络是否连接
     * @return 是否连接
     */
    fun isConnected(): Boolean {
        return try {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
                val network = connectivityManager.activeNetwork ?: return false
                val capabilities = connectivityManager.getNetworkCapabilities(network) ?: return false
                capabilities.hasCapability(NetworkCapabilities.NET_CAPABILITY_INTERNET)
            } else {
                @Suppress("DEPRECATION")
                val networkInfo = connectivityManager.activeNetworkInfo
                networkInfo?.isConnected == true
            }
        } catch (e: Exception) {
            false
        }
    }

    /**
     * 检查网络是否可用（可上网）
     * @return 是否可用
     */
    fun isAvailable(): Boolean {
        return isConnected() && checkInternetAccess()
    }

    /**
     * 检查是否使用 WiFi
     * @return 是否是 WiFi
     */
    fun isWifi(): Boolean {
        return try {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
                val network = connectivityManager.activeNetwork ?: return false
                val capabilities = connectivityManager.getNetworkCapabilities(network) ?: return false
                capabilities.hasTransport(NetworkCapabilities.TRANSPORT_WIFI)
            } else {
                @Suppress("DEPRECATION")
                connectivityManager.activeNetworkInfo?.type == ConnectivityManager.TYPE_WIFI
            }
        } catch (e: Exception) {
            false
        }
    }

    /**
     * 检查是否使用移动网络
     * @return 是否是移动网络
     */
    fun isMobile(): Boolean {
        return try {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
                val network = connectivityManager.activeNetwork ?: return false
                val capabilities = connectivityManager.getNetworkCapabilities(network) ?: return false
                capabilities.hasTransport(NetworkCapabilities.TRANSPORT_CELLULAR)
            } else {
                @Suppress("DEPRECATION")
                connectivityManager.activeNetworkInfo?.type == ConnectivityManager.TYPE_MOBILE
            }
        } catch (e: Exception) {
            false
        }
    }

    /**
     * 获取当前网络状态
     * @return 网络状态
     */
    fun getNetworkState(): NetworkState {
        if (!isConnected()) return NetworkState.disconnected()

        return NetworkState(
            isConnected = true,
            isWifi = isWifi(),
            isMobile = isMobile(),
            isAvailable = checkInternetAccess()
        )
    }

    /**
     * 测试互联网访问（通过连接公共DNS）
     * @return 是否可访问互联网
     */
    private fun checkInternetAccess(): Boolean {
        return try {
            val url = URL("https://www.baidu.com")
            val connection = url.openConnection() as HttpURLConnection
            connection.connectTimeout = 3000
            connection.readTimeout = 3000
            connection.requestMethod = "HEAD"
            connection.responseCode == HttpURLConnection.HTTP_OK
        } catch (e: Exception) {
            false
        }
    }

    /**
     * 开始监听网络状态变化
     */
    fun startNetworkMonitoring() {
        stopNetworkMonitoring()

        val request = NetworkRequest.Builder()
            .addCapability(NetworkCapabilities.NET_CAPABILITY_INTERNET)
            .build()

        networkCallback = object : ConnectivityManager.NetworkCallback() {
            override fun onAvailable(network: Network) {
                _networkState.postValue(getNetworkState())
            }

            override fun onLost(network: Network) {
                _networkState.postValue(NetworkState.disconnected())
            }

            override fun onCapabilitiesChanged(
                network: Network,
                networkCapabilities: NetworkCapabilities
            ) {
                _networkState.postValue(getNetworkState())
            }
        }

        networkCallback?.let {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                connectivityManager.registerDefaultNetworkCallback(it)
            } else {
                @Suppress("DEPRECATION")
                connectivityManager.registerNetworkCallback(request, it)
            }
        }

        // 初始状态
        _networkState.postValue(getNetworkState())
    }

    /**
     * 停止监听网络状态变化
     */
    fun stopNetworkMonitoring() {
        networkCallback?.let {
            connectivityManager.unregisterNetworkCallback(it)
        }
        networkCallback = null
    }

    /**
     * 检查URL是否可访问
     * @param urlString URL字符串
     * @param timeout 超时时间（毫秒）
     * @return 是否可访问
     */
    suspend fun isUrlReachable(urlString: String, timeout: Int = 5000): Boolean = suspendCancellableCoroutine { cont ->
        try {
            val url = URL(urlString)
            val connection = url.openConnection() as HttpURLConnection
            connection.connectTimeout = timeout
            connection.readTimeout = timeout
            connection.requestMethod = "HEAD"

            Thread {
                try {
                    val reachable = connection.responseCode == HttpURLConnection.HTTP_OK
                    connection.disconnect()
                    if (cont.isActive) cont.resume(reachable)
                } catch (e: Exception) {
                    if (cont.isActive) cont.resume(false)
                }
            }.start()
        } catch (e: Exception) {
            if (cont.isActive) cont.resume(false)
        }
    }

    /**
     * 获取网络类型描述
     * @return 网络类型描述字符串
     */
    fun getNetworkTypeDescription(): String {
        return when {
            !isConnected() -> "无网络"
            isWifi() -> "WiFi"
            isMobile() -> "移动网络"
            else -> "未知网络"
        }
    }

    /**
     * 检查是否需要显示网络警告
     * @return 是否需要显示
     */
    fun shouldShowNetworkWarning(): Boolean {
        val state = getNetworkState()
        return !state.isConnected || state.isMobile
    }

    /**
     * 创建网络监听器
     * @param onNetworkChanged 网络状态变化回调
     */
    fun createNetworkListener(onNetworkChanged: (NetworkState) -> Unit): ConnectivityManager.NetworkCallback {
        return object : ConnectivityManager.NetworkCallback() {
            override fun onAvailable(network: Network) {
                onNetworkChanged(getNetworkState())
            }

            override fun onLost(network: Network) {
                onNetworkChanged(NetworkState.disconnected())
            }
        }
    }

    /**
     * 注册网络监听器
     * @param callback 网络回调对象
     */
    fun registerNetworkCallback(callback: ConnectivityManager.NetworkCallback) {
        val request = NetworkRequest.Builder()
            .addCapability(NetworkCapabilities.NET_CAPABILITY_INTERNET)
            .build()

        connectivityManager.registerNetworkCallback(request, callback)
    }

    /**
     * 注销网络监听器
     * @param callback 网络回调对象
     */
    fun unregisterNetworkCallback(callback: ConnectivityManager.NetworkCallback) {
        connectivityManager.unregisterNetworkCallback(callback)
    }
}

package com.shanfuchun.courtassistant.util.share

import android.content.ActivityNotFoundException
import android.content.Context
import android.content.Intent
import android.content.pm.PackageManager
import android.net.Uri
import android.widget.Toast
import androidx.core.content.FileProvider
import com.shanfuchun.courtassistant.R
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import java.io.File
import java.io.FileInputStream
import java.util.zip.ZipEntry
import java.util.zip.ZipOutputStream

/**
 * 微信分享工具类
 *
 * 支持单文件和多文件打包分享到微信
 * 提供多种分享目标选择（微信、QQ、钉钉等）
 */
class WeChatShareUtil(private val context: Context) {

    companion object {
        // 微信包名
        const val WECHAT_PACKAGE_NAME = "com.tencent.mm"

        // 尝试多个可能的分享入口类
        val POSSIBLE_SHARE_CLASSES = listOf(
            "com.tencent.mm.ui.tools.ShareToTimeLineActivity",  // 朋友圈分享
            "com.tencent.mm.ui.tools.ShareImgUI",              // 图片分享
            "com.tencent.mm.ui.tools.ShareToQQ",              // QQ分享
        )

        /**
         * 检查微信是否安装
         */
        fun isWeChatAvailable(context: Context): Boolean {
            return try {
                context.packageManager.getPackageInfo(WECHAT_PACKAGE_NAME, 0) != null
            } catch (e: PackageManager.NameNotFoundException) {
                false
            }
        }

        /**
         * 检查应用是否安装
         */
        fun isAppAvailable(context: Context, packageName: String): Boolean {
            return try {
                context.packageManager.getPackageInfo(packageName, 0) != null
            } catch (e: PackageManager.NameNotFoundException) {
                false
            }
        }

        /**
         * 创建分享Intent
         */
        fun createShareIntent(
            packageName: String,
            className: String? = null,
            uri: Uri,
            description: String = "法院文档"
        ): Intent {
            return Intent(Intent.ACTION_SEND).apply {
                type = "*/*"
                flags = Intent.FLAG_GRANT_READ_URI_PERMISSION
                setPackage(packageName)
                className?.let { setClassName(packageName, it) }
                putExtra(Intent.EXTRA_STREAM, uri)
                putExtra(Intent.EXTRA_TEXT, description)
                putExtra("KDescription", description)
                putExtra("KFilePath", uri.path)
            }
        }
    }

    /**
     * 分享目标数据类
     */
    data class ShareTarget(
        val packageName: String,
        val appName: String,
        val iconRes: Int = 0,
        val priority: Int = 0,
        val className: String? = null
    )

    /**
     * 获取可用的分享目标列表
     */
    fun getAvailableShareTargets(): List<ShareTarget> {
        val targets = mutableListOf<ShareTarget>()

        // 检查微信
        if (isWeChatAvailable(context)) {
            targets.add(ShareTarget(
                packageName = WECHAT_PACKAGE_NAME,
                appName = "微信",
                priority = 1,
                className = POSSIBLE_SHARE_CLASSES[0]
            ))
        }

        // 检查QQ
        if (isAppAvailable(context, "com.tencent.mobileqq")) {
            targets.add(ShareTarget(
                packageName = "com.tencent.mobileqq",
                appName = "QQ",
                priority = 2
            ))
        }

        // 检查钉钉
        if (isAppAvailable(context, "com.alibaba.android.rimet")) {
            targets.add(ShareTarget(
                packageName = "com.alibaba.android.rimet",
                appName = "钉钉",
                priority = 3
            ))
        }

        // 检查企业微信
        if (isAppAvailable(context, "com.tencent.wework")) {
            targets.add(ShareTarget(
                packageName = "com.tencent.wework",
                appName = "企业微信",
                priority = 4
            ))
        }

        return targets.sortedBy { it.priority }
    }

    /**
     * 分享单个文件
     */
    suspend fun shareFile(file: File): Boolean = withContext(Dispatchers.Main) {
        try {
            val uri = createFileUri(file)
            val targets = getAvailableShareTargets()

            if (targets.isEmpty()) {
                // 没有可用的分享应用，使用系统分享
                shareWithSystemChooser(file)
                return@withContext true
            }

            // 默认使用微信分享
            val weChatTarget = targets.find { it.packageName == WECHAT_PACKAGE_NAME }
            if (weChatTarget != null) {
                shareToTarget(weChatTarget, uri)
                return@withContext true
            }

            // 使用第一个可用应用
            shareToTarget(targets[0], uri)
            true
        } catch (e: Exception) {
            e.printStackTrace()
            Toast.makeText(context, "分享失败: ${e.message}", Toast.LENGTH_SHORT).show()
            false
        }
    }

    /**
     * 分享多个文件（打包为ZIP）
     */
    suspend fun shareFiles(files: List<File>): Boolean = withContext(Dispatchers.IO) {
        try {
            val zipFile = createZipFile(files)
            withContext(Dispatchers.Main) {
                shareFile(zipFile)
            }
            true
        } catch (e: Exception) {
            e.printStackTrace()
            withContext(Dispatchers.Main) {
                Toast.makeText(context, "打包失败: ${e.message}", Toast.LENGTH_SHORT).show()
            }
            false
        }
    }

    /**
     * 创建 ZIP 文件
     */
    private suspend fun createZipFile(files: List<File>): File = withContext(Dispatchers.IO) {
        val timestamp = System.currentTimeMillis()
        val zipFile = File(context.cacheDir, "court_docs_$timestamp.zip")

        ZipOutputStream(zipFile.outputStream()).use { zos ->
            for (file in files) {
                if (file.exists()) {
                    val entry = ZipEntry(file.name)
                    zos.putNextEntry(entry)
                    FileInputStream(file).use { input ->
                        input.copyTo(zos)
                    }
                    zos.closeEntry()
                }
            }
        }

        return@withContext zipFile
    }

    /**
     * 分享到指定目标
     */
    private fun shareToTarget(target: ShareTarget, uri: Uri) {
        try {
            val intent = createShareIntent(
                packageName = target.packageName,
                className = target.className,
                uri = uri,
                description = "法院文档"
            )
            context.startActivity(intent)
        } catch (e: ActivityNotFoundException) {
            Toast.makeText(context, "未找到${target.appName}", Toast.LENGTH_SHORT).show()
        } catch (e: Exception) {
            Toast.makeText(context, "分享失败: ${e.message}", Toast.LENGTH_SHORT).show()
        }
    }

    /**
     * 使用系统分享选择器
     */
    private fun shareWithSystemChooser(file: File) {
        val uri = createFileUri(file)
        val intent = Intent(Intent.ACTION_SEND).apply {
            type = "*/*"
            flags = Intent.FLAG_GRANT_READ_URI_PERMISSION
            putExtra(Intent.EXTRA_STREAM, uri)
            putExtra(Intent.EXTRA_TEXT, "法院文档")
        }
        context.startActivity(Intent.createChooser(intent, "分享到"))
    }

    /**
     * 创建文件 URI
     */
    private fun createFileUri(file: File): Uri {
        return FileProvider.getUriForFile(
            context,
            "${context.packageName}.fileprovider",
            file
        )
    }

    /**
     * 分享文本到微信
     */
    fun shareTextToWeChat(text: String): Boolean {
        return if (isWeChatAvailable(context)) {
            try {
                val intent = Intent().apply {
                    action = Intent.ACTION_SEND
                    setPackage(WECHAT_PACKAGE_NAME)
                    type = "text/plain"
                    putExtra(Intent.EXTRA_TEXT, text)
                }
                context.startActivity(intent)
                true
            } catch (e: Exception) {
                false
            }
        } else {
            Toast.makeText(context, "未安装微信", Toast.LENGTH_SHORT).show()
            false
        }
    }

    /**
     * 打开微信应用
     */
    fun openWeChat(): Boolean {
        return if (isWeChatAvailable(context)) {
            try {
                val intent = context.packageManager.getLaunchIntentForPackage(WECHAT_PACKAGE_NAME)
                context.startActivity(intent)
                true
            } catch (e: Exception) {
                false
            }
        } else {
            Toast.makeText(context, "未安装微信", Toast.LENGTH_SHORT).show()
            false
        }
    }
}

package com.shanfuchun.courtassistant.ui

import android.app.ProgressDialog
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Toast
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.fragment.app.Fragment
import androidx.fragment.app.activityViewModels
import androidx.lifecycle.lifecycleScope
import androidx.lifecycle.observe
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.recyclerview.widget.RecyclerView
import com.shanfuchun.courtassistant.R
import com.shanfuchun.courtassistant.databinding.FragmentDocsBinding
import com.shanfuchun.courtassistant.ui.adapter.DocAdapter
import com.shanfuchun.courtassistant.ui.adapter.DocumentItem
import com.shanfuchun.courtassistant.util.share.ShareTarget
import com.shanfuchun.courtassistant.util.share.WeChatShareUtil
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.delay
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import java.io.File
import java.util.zip.ZipEntry
import java.util.zip.ZipOutputStream

/**
 * 文档管理 Fragment（增强版）
 *
 * 新增功能：
 * 1. 单选/多选模式切换
 * 2. 多选后显示批量操作栏
 * 3. 打包ZIP压缩分享
 * 4. 分享到微信支持
 */
class DocsFragment : Fragment() {

    private var _b: FragmentDocsBinding? = null
    private val b get() = _b!!
    private val vm: MainViewModel by activityViewModels()

    // 选择模式
    enum class SelectionMode {
        SINGLE,      // 单选模式
        MULTI        // 多选模式
    }

    private var selectionMode: SelectionMode = SelectionMode.SINGLE
    private val selectedDocIds = mutableSetOf<Long>()
    private var docAdapter: DocAdapter? = null

    override fun onCreateView(inflater: LayoutInflater, container: ViewGroup?, savedInstanceState: Bundle?): View {
        _b = FragmentDocsBinding.inflate(inflater, container, false)
        return b.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        setupToolbar()
        setupRecyclerView()
        observeData()
        setupClickListeners()
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _b = null
        docAdapter = null
    }

    /**
     * 设置工具栏
     */
    private fun setupToolbar() {
        (requireActivity() as AppCompatActivity).setSupportActionBar(b.toolbar)
        b.toolbar.title = "文档管理"
        b.toolbar.setNavigationIcon(R.drawable.ic_folder)
    }

    /**
     * 设置列表
     */
    private fun setupRecyclerView() {
        // 文档列表
        b.rvDocs.layoutManager = LinearLayoutManager(requireContext())
        docAdapter = DocAdapter(
            onClick = { doc -> previewPdf(doc) },
            onSelect = { doc -> toggleSelection(doc.id) },
            onLongPress = { doc -> showDocumentContextMenu(doc) }
        )
        b.rvDocs.adapter = docAdapter

        // 空状态处理
        updateEmptyState(emptyList())
    }

    /**
     * 观察数据
     */
    private fun observeData() {
        // 观察文档列表
        vm.currentDocs.observe(viewLifecycleOwner) { list ->
            docAdapter?.submitList(list)
            updateEmptyState(list)
            updateSelectionFromAdapter()
        }

        // 观察日历同步状态
        vm.calendarSyncMap.observe(viewLifecycleOwner) { map ->
            docAdapter?.updateCalendarSync(map)
        }
    }

    /**
     * 设置点击监听器
     */
    private fun setupClickListeners() {
        // 全选按钮
        b.btnSelectAll.setOnClickListener {
            toggleSelectionMode()
        }

        // 删除按钮
        b.btnDelete.setOnClickListener {
            handleDeleteClick()
        }

        // 批量操作按钮
        b.btnShareWeChat.setOnClickListener {
            handleShareWeChatClick()
        }
    }

    /**
     * 切换选择模式
     */
    private fun toggleSelectionMode() {
        when (selectionMode) {
            SelectionMode.SINGLE -> {
                // 切换到多选模式
                selectionMode = SelectionMode.MULTI
                b.btnSelectAll.text = "取消全选"
                showBatchActionBar(true)
                docAdapter?.setMultiSelectMode(true)
            }
            SelectionMode.MULTI -> {
                // 切换到单选模式
                selectionMode = SelectionMode.SINGLE
                b.btnSelectAll.text = "全选"
                showBatchActionBar(false)
                docAdapter?.setMultiSelectMode(false)
                // 清空选择
                clearAllSelection()
            }
        }
    }

    /**
     * 显示批量操作栏
     */
    private fun showBatchActionBar(show: Boolean) {
        b.selectionActionBar.visibility = if (show) View.VISIBLE else View.GONE
        b.tvBatchActionHint.visibility = if (show) View.VISIBLE else View.GONE
        b.btnDelete.text = if (show) "删除选中" else "删除"
        b.btnShareWeChat.visibility = if (show) View.VISIBLE else View.GONE

        // 更新提示文本
        b.tvSelectionHint.text = if (show) {
            val count = selectedDocIds.size
            "已选 $count 项"
        } else {
            ""
        }
    }

    /**
     * 更新空状态
     */
    private fun updateEmptyState(list: List<DocumentItem>) {
        val hasDocuments = list.any { it is DocumentItem.Document }
        b.tvEmpty.visibility = if (!hasDocuments) View.VISIBLE else View.GONE
        b.rvDocs.visibility = if (hasDocuments) View.VISIBLE else View.GONE
    }

    /**
     * 从适配器更新选择状态
     */
    private fun updateSelectionFromAdapter() {
        selectedDocIds.clear()
        docAdapter?.getSelectedIds(selectedDocIds)
    }

    /**
     * 清空所有选择
     */
    private fun clearAllSelection() {
        selectedDocIds.clear()
        docAdapter?.clearSelection()
        updateActionBar()
    }

    /**
     * 更新操作栏状态
     */
    private fun updateActionBar() {
        val count = selectedDocIds.size
        if (count > 0) {
            b.tvSelectionHint.text = "已选 $count 项"
        } else {
            b.tvSelectionHint.text = ""
        }
    }

    /**
     * 切换单个文档选择状态
     */
    private fun toggleSelection(docId: Long) {
        if (selectedDocIds.contains(docId)) {
            selectedDocIds.remove(docId)
        } else {
            selectedDocIds.add(docId)
        }
        updateActionBar()
    }

    /**
     * 处理删除点击
     */
    private fun handleDeleteClick() {
        when (selectionMode) {
            SelectionMode.SINGLE -> {
                // 单选模式：提示进入多选模式
                Toast.makeText(requireContext(), "长按文档进入多选模式", Toast.LENGTH_SHORT).show()
            }
            SelectionMode.MULTI -> {
                // 多选模式：显示删除选项对话框
                val count = selectedDocIds.size
                if (count == 0) {
                    Toast.makeText(requireContext(), "请先选择文档", Toast.LENGTH_SHORT).show()
                    return
                }
                showMultiDeleteDialog(count)
            }
        }
    }

    /**
     * 多选删除对话框
     */
    private fun showMultiDeleteDialog(count: Int) {
        val options = arrayOf("仅删除记录（保留文件）", "删除记录和文件")
        AlertDialog.Builder(requireContext())
            .setTitle("确认删除")
            .setMessage("将删除 $count 个文档")
            .setSingleChoiceItems(options, -1) { _, _ -> }
            .setPositiveButton("删除") { dialog, _ ->
                val selectedOption = (dialog as AlertDialog).listView.checkedItemPosition
                when (selectedOption) {
                    0 -> performDelete(selectedDocIds.toList(), deleteFiles = false)
                    1 -> performDelete(selectedDocIds.toList(), deleteFiles = true)
                    else -> performDelete(selectedDocIds.toList(), deleteFiles = false)
                }
            }
            .setNegativeButton("取消", null)
            .show()
    }

    /**
     * 执行删除操作
     */
    private fun performDelete(ids: List<Long>, deleteFiles: Boolean) {
        lifecycleScope.launch {
            try {
                // 显示进度
                Toast.makeText(requireContext(), "正在删除...", Toast.LENGTH_SHORT).show()

                if (deleteFiles) {
                    // 显示文件路径并删除
                    vm.getDocsByIds(ids) { docs ->
                        docs.forEach { doc ->
                            val file = File(doc.filePath)
                            if (file.exists()) {
                                file.delete()
                            }
                        }
                    }
                }

                // 删除记录
                vm.deleteDocs(ids, deleteFiles)

                // 清空选择
                clearAllSelection()

                // 完成提示
                Toast.makeText(requireContext(), "删除完成", Toast.LENGTH_SHORT).show()
            } catch (e: Exception) {
                Toast.makeText(requireContext(), "删除失败: ${e.message}", Toast.LENGTH_SHORT).show()
            }
        }
    }

    /**
     * 处理微信分享点击
     */
    private fun handleShareWeChatClick() {
        val count = selectedDocIds.size
        if (count == 0) {
            Toast.makeText(requireContext(), "请先选择文档", Toast.LENGTH_SHORT).show()
            return
        }

        when (count) {
            1 -> {
                // 单个文件：直接分享
                vm.getDocsByIds(selectedDocIds.toList()) { docs ->
                    docs.firstOrNull()?.let { shareToWeChat(it) }
                }
            }
            else -> {
                // 多个文件：压缩后分享
                showCompressionDialog()
            }
        }
    }

    /**
     * 压缩对话框
     */
    private fun showCompressionDialog() {
        // 获取选中的文档
        val docs = mutableListOf<DocumentItem.Document>()
        docAdapter?.getSelectedDocuments(docs)

        if (docs.isEmpty()) {
            Toast.makeText(requireContext(), "请先选择文档", Toast.LENGTH_SHORT).show()
            return
        }

        // 计算文件总大小
        val totalSize = docs.sumOf { it.record.fileSize }
        val totalSizeMB = totalSize / (1024 * 1024)
        val sizeText = if (totalSizeMB < 1) {
            String.format("%.2f MB", totalSize.toDouble() / (1024 * 1024))
        } else {
            "$totalSizeMB MB"
        }

        // 显示进度对话框
        val progressDialog = ProgressDialog(requireContext()).apply {
            setMessage("正在打包 $sizeText...")
            setCancelable(false)
            setProgressStyle(ProgressDialog.STYLE_HORIZONTAL)
            max = docs.size
        }
        progressDialog.show()

        lifecycleScope.launch(Dispatchers.IO) {
            try {
                // 创建ZIP文件
                val zipFile = createZipFile(docs, progressDialog)

                withContext(Dispatchers.Main) {
                    progressDialog.dismiss()
                    // 调用微信分享
                    shareZipToWeChat(zipFile, docs.size)
                }
            } catch (e: Exception) {
                withContext(Dispatchers.Main) {
                    progressDialog.dismiss()
                    Toast.makeText(requireContext(), "打包失败：${e.message}", Toast.LENGTH_SHORT).show()
                }
            }
        }
    }

    /**
     * 创建ZIP文件
     */
    private suspend fun createZipFile(
        docs: List<DocumentItem.Document>,
        progress: ProgressDialog
    ): File = withContext(Dispatchers.IO) {
        val timestamp = System.currentTimeMillis()
        val zipFile = File(requireContext().cacheDir, "court_docs_$timestamp.zip")

        var processedCount = 0

        ZipOutputStream(zipFile.outputStream()).use { zos ->
            for (doc in docs) {
                val file = File(doc.record.filePath)
                if (!file.exists()) {
                    processedCount++
                    withContext(Dispatchers.Main) {
                        progress.progress = processedCount
                    }
                    delay(10)
                    continue
                }

                // 添加文件到ZIP
                val entry = ZipEntry(doc.record.fileName)
                zos.putNextEntry(entry)
                file.inputStream().use { input ->
                    input.copyTo(zos)
                }
                zos.closeEntry()

                processedCount++
                withContext(Dispatchers.Main) {
                    progress.progress = processedCount
                }
                delay(50)
            }
        }

        return@withContext zipFile
    }

    /**
     * 分享ZIP到微信
     */
    private fun shareZipToWeChat(zipFile: File, fileCount: Int) {
        val shareUtil = WeChatShareUtil(requireContext())

        // 获取可用分享目标
        val targets = shareUtil.getAvailableShareTargets()

        if (targets.isEmpty()) {
            // 没有任何分享应用，使用系统分享
            shareZipSystem(zipFile, fileCount)
            return
        }

        // 显示分享选择对话框
        showShareTargetDialog(targets, zipFile, fileCount)
    }

    /**
     * 分享目标选择对话框
     */
    private fun showShareTargetDialog(
        targets: List<ShareTarget>,
        zipFile: File,
        fileCount: Int
    ) {
        val targetNames = targets.map {
            "${it.appName} ${if (it.priority == 1) "(推荐)" else ""}"
        }.toTypedArray()

        AlertDialog.Builder(requireContext())
            .setTitle("选择分享方式")
            .setSingleChoiceItems(targetNames, 0) { _, _ -> }
            .setPositiveButton("分享") { dialog, _ ->
                val selectedPosition = (dialog as AlertDialog).listView.checkedItemPosition
                if (selectedPosition >= 0 && selectedPosition < targets.size) {
                    val target = targets[selectedPosition]
                    shareToTarget(target, zipFile, fileCount)
                }
            }
            .setNegativeButton("取消") { _ ->
                // 用户取消，清理ZIP文件
                zipFile.delete()
            }
            .show()
    }

    /**
     * 分享到指定目标
     */
    private fun shareToTarget(
        target: ShareTarget,
        zipFile: File,
        fileCount: Int
    ) {
        val uri = com.shanfuchun.courtassistant.util.file.UriUtils.createFileUri(
            requireContext(),
            zipFile
        )

        when (target.packageName) {
            WeChatShareUtil.WECHAT_PACKAGE_NAME -> {
                // 分享到微信
                shareToWeChatIntent(uri, fileCount)
            }
            else -> {
                // 其他应用使用系统分享
                shareSystemIntent(uri, fileCount, target.appName)
            }
        }
    }

    /**
     * 分享到微信
     */
    private fun shareToWeChatIntent(uri: Uri, fileCount: Int) {
        val intent = WeChatShareUtil.createShareIntent(
            packageName = WeChatShareUtil.WECHAT_PACKAGE_NAME,
            className = WeChatShareUtil.POSSIBLE_SHARE_CLASSES[0],
            uri = uri
        ).apply {
            putExtra("KDescription", "$fileCount 个法院文档")
            putExtra("KFilePath", uri.path)
        }

        try {
            startActivity(intent)
        } catch (e: Exception) {
            // 微信未安装或分享失败
            showWeChatInstallDialog()
        }
    }

    /**
     * 微信未安装对话框
     */
    private fun showWeChatInstallDialog() {
        AlertDialog.Builder(requireContext())
            .setTitle("分享提示")
            .setMessage("未检测到微信应用，是否前往安装？")
            .setPositiveButton("安装") { _, _ ->
                openWeChatInGooglePlay()
            }
            .setNegativeButton("取消") { _ ->
                Toast.makeText(requireContext(), "已取消分享", Toast.LENGTH_SHORT).show()
            }
            .setNeutralButton("其他方式") { _, _ ->
                // 降级使用系统分享
                Toast.makeText(requireContext(), "请选择其他分享方式", Toast.LENGTH_SHORT).show()
            }
            .show()
    }

    /**
     * 使用系统分享ZIP
     */
    private fun shareZipSystem(zipFile: File, fileCount: Int) {
        val uri = com.shanfuchun.courtassistant.util.file.UriUtils.createFileUri(
            requireContext(),
            zipFile
        )

        val intent = Intent(Intent.ACTION_SEND).apply {
            type = "application/zip"
            flags = Intent.FLAG_GRANT_READ_URI_PERMISSION
            putExtra(Intent.EXTRA_STREAM, uri)
            putExtra(Intent.EXTRA_TEXT, "$fileCount 个法院文档")
        }

        startActivity(Intent.createChooser(intent, "分享到"))
    }

    /**
     * 使用系统分享Intent
     */
    private fun shareSystemIntent(uri: Uri, fileCount: Int, appName: String) {
        val intent = Intent(Intent.ACTION_SEND).apply {
            type = "*/*"
            flags = Intent.FLAG_GRANT_READ_URI_PERMISSION
            putExtra(Intent.EXTRA_STREAM, uri)
            putExtra(Intent.EXTRA_TEXT, "$fileCount 个法院文档")
        }

        try {
            startActivity(Intent.createChooser(intent, "分享到 $appName"))
        } catch (e: Exception) {
            Toast.makeText(requireContext(), "分享失败", Toast.LENGTH_SHORT).show()
        }
    }

    /**
     * 预览PDF文档
     */
    private fun previewPdf(doc: DocumentItem.Document) {
        val file = File(doc.record.filePath)
        if (!file.exists()) {
            Toast.makeText(requireContext(), "文件不存在", Toast.LENGTH_SHORT).show()
            return
        }

        val uri = com.shanfuchun.courtassistant.util.file.UriUtils.createFileUri(
            requireContext(),
            file
        )

        val intent = Intent(Intent.ACTION_VIEW).apply {
            setDataAndType(uri, "application/pdf")
            flags = Intent.FLAG_GRANT_READ_URI_PERMISSION
        }

        try {
            startActivity(intent)
        } catch (e: Exception) {
            Toast.makeText(requireContext(), "无法打开PDF", Toast.LENGTH_SHORT).show()
        }
    }

    /**
     * 显示文档上下文菜单
     */
    private fun showDocumentContextMenu(doc: DocumentItem.Document) {
        val options = arrayOf("预览", "分享", "删除", "取消")
        AlertDialog.Builder(requireContext())
            .setTitle(doc.record.fileName)
            .setItems(options) { _, which ->
                when (which) {
                    0 -> previewPdf(doc)
                    1 -> shareToWeChat(doc)
                    2 -> performDelete(listOf(doc.id), deleteFiles = true)
                }
            }
            .show()
    }

    /**
     * 分享单个文档到微信
     */
    private fun shareToWeChat(doc: DocumentItem.Document) {
        val file = File(doc.record.filePath)
        if (!file.exists()) {
            Toast.makeText(requireContext(), "文件不存在", Toast.LENGTH_SHORT).show()
            return
        }

        lifecycleScope.launch {
            val shareUtil = WeChatShareUtil(requireContext())
            shareUtil.shareFile(file)
        }
    }

    /**
     * 打开微信安装页面
     */
    private fun openWeChatInGooglePlay() {
        try {
            val intent = Intent(Intent.ACTION_VIEW).apply {
                data = Uri.parse("market://details?id=com.tencent.mm")
            }
            startActivity(intent)
        } catch (e: Exception) {
            Toast.makeText(requireContext(), "无法打开应用商店", Toast.LENGTH_SHORT).show()
        }
    }
}

